!function(){try{var e="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},a=(new e.Error).stack;a&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[a]="1dace247-d335-4e04-825c-ae281b616418",e._sentryDebugIdIdentifier="sentry-dbid-1dace247-d335-4e04-825c-ae281b616418")}catch(e){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[628],{24628:function(e,a,o){o.r(a),o.d(a,{locale:function(){return i}});var n=o(23068),r=JSON.parse('{"title":"Reconexión de protocolo","description":"Bienvenido de vuelta a Talos-II, Endministrator.","guide":{"character":"Perlica","lines":"Endmin, ¿cómo te fue en tus vacaciones? ¡Pasaron muchas cosas a bordo de la Dijiang y los operadores de nuestra División médica no paraban de pedirme que te recordara registrarte para tu examen físico! Todos te extrañan, y yo... Yo también te estoy esperando, Endmin.","button":"Reconexión de protocolo"},"home":{"title":"Reconexión de protocolo","timeCount":"{{DD}}D {{HH}}H","tabs":{"checkIn":"Inicio de sesión de reconexión","task":"Tareas de reconexión","survey":"Encuesta de retorno"},"checkIn":{"title":"Inicio de sesión de reconexión","intro":"¡Participa en el evento [Inicio de sesión de reconexión] durante 7 días y reclama [Oroberilio]×2000 y otras recompensas!"},"task":{"intro":"Participa en el evento [Tareas de reconexión] y completa varias tareas para obtener <b>[Permiso de C.R. Básica]×4</b> y otras recompensas.","taskStatus":{"claimable":"Reclamar","ongoing":"Incompleto","claimed":"Reclamado"},"claimAvailable":"Reclamar todo","currentPoint":"Puntos actuales","taskContent":{"daily_login":"Inicia sesión en el juego 1 vez al día (esto se puede completar 7 veces)","deploy_factory":"Coloca cualquier instalación de la Fábrica del CAI","battle_enemy":"Derrota a 10 enemigos","clear_stage":"Completa cualquier Espacio de protocolo 1 vez","manufacture":"En la Dijiang, reclama productos de cualquier cabina de producción 1 vez","upgrade_role_level":"Sube de nivel a cualquier operador 1 vez","collect_ore":"Recolecta cualquier mineral 1 vez","trade_goods":"Comercia con cualquier puesto de avanzada 1 vez","buy_goods":"Compra artículos en cualquier sistema de redistribución de existencias 1 vez","trade_credit":"Compra artículos en la Tienda de créditos 1 vez","collect_item":"Recolecta 8 Boletes rosa","ap_cost":"Gasta 1000 Puntos de cordura","boss_challenge":"Completa cualquier desafío de Re-crisis 1 vez","world_battle":"Aluvión energético limpio 1 vez (Aluvión energético temporal también cuenta)"}},"minimumTimeCount":"<1H","survey":{"surveyStatus":{"not_started":"Sin iniciar","claimed":"Completada"},"goToButton":"Ir","unlockText":"Se desbloquea después de {{timeCount}}","rewardTip":"Completa la encuesta para obtener","surveyContent":{"survey_1":"Encuesta de retorno del primer día","survey_2":"Encuesta sobre la experiencia de retorno"},"callbackModal":{"title":"NOTIFICACIÓN DEL SISTEMA","content":"Ve a la página nueva para participar en la encuesta.","button":"Completada"}}},"rule":{"title":"Detalles del evento [Reconexión de protocolo]","content":"<b>- Requisitos de participación -</b>\\n<span>· Nivel de Autoridad del Endministrator ≥ 3</span>\\n<span>· Completa la misión principal [Capítulo i Proceso i: El reinicio del valle]</span>\\n<span>· No has iniciado sesión en el juego por ≥ 21 días consecutivos</span>\\n<span>· Participaste en el último evento [Reconexión de protocolo] hace ≥ 42 días</span>\\n<span>· La duración del estado Regreso del Endministrator es la misma que el periodo del evento [Reconexión de protocolo]</span>\\n\\n<b>- Reglas del Evento -</b>\\n<span>· Visitar por primera vez la página del evento [Reconexión de protocolo] te da una recompensa de Reconexión de protocolo, Endministrator.</span>\\n<span>· Durante el evento, visita la página [Reconexión de protocolo] y gana recompensas participando en [Inicio de sesión de reconexión] y [Tareas de reconexión].</span>\\n<span>· Durante el evento, inicia sesión en [Inicio de sesión de reconexión] todos los días para ganar recompensas. Se puede iniciar sesión diariamente 7 veces.</span>\\n<span>· Durante el evento, completa varias [Tareas de reconexión] para ganar puntos del evento y recompensas. Reunir suficientes puntos también otorga recompensas extra.</span>\\n<span>El conteo de datos de [Tareas de reconexión] puede tener ligeros retrasos. Después de completar los requisitos de la tarea, espera 2-5 minutos para que los datos se sincronicen.</span>\\n<span>· Todas las recompensas del evento se enviarán a tu Correo del juego. Los correos de recompensa expirarán en 30 días, así que reclámalos a tiempo, Endministrator.</span>\\n<span>· El evento terminará 14 días después de tu participación y cerrará a las 4:00 a. m. (hora del servidor).</span>"},"rewardModal":{"title":"Recompensas obtenidas","prompt":"Estas recompensas se enviaron a tu Correo. No olvides reclamarlas, Endmin.","pointTitle":"Gana puntos","closeTip":"Haz clic para cerrar","closeTip_PC":"Haz clic para cerrar","closeTip_MB":"Toca para cerrar"},"gameItem":{"item_gold":{"name":"T-Creds","usage":"TC para abreviar. Esta divisa es reconocida y utilizada en muchos lugares.","desc":"Moneda popular equipada con tecnologías avanzadas contra la falsificación. Sabes que es buen dinero si puedes comprar cosas con él."},"item_diamond":{"name":"Oroberilio","usage":"Un material artificial que se usa a menudo para reclutar a operadores.","desc":"Un producto especial de la Origeometría de corte. Estas piedras son extremadamente populares debido a su belleza y a su amplia gama de usos."},"item_expcard_stage1_high":{"name":"Registro de Combate Avanzado","usage":"Un material que brinda muchos puntos de EXP para hacer subir de nivel a los operadores de Nvl. 1-60.","desc":"Un dispositivo de almacenamiento con grabaciones en video de combates. Los nuevos operadores pueden usarlo para adquirir conocimientos de combate. Además, está enriquecido con simulaciones de batallas históricas, permitiendo a los observadores comprender mejor la implacable brutalidad de los conflictos reales librados en Talos-II"},"item_weapon_expcard_high":{"name":"Set de inspector de armas","usage":"Un material que proporciona muchos puntos de EXP de arma.","desc":"Un conjunto de herramientas de un solo uso con tecnología del CAI. Proporciona una inspección automatizada en profundidad de toda la estructura del arma. También repara los daños internos del material y mejora notablemente el rendimiento del arma."},"item_char_break_stage_1_2":{"name":"Protodisco","usage":"Un material que permite ascender a los operadores a E1 o E2.","desc":"Un disco especial fabricado mediante el uso del tecno protocolo y procesos estándar de grabado de datos. Se utiliza comúnmente con otros dispositivos para aliviar eficazmente la fatiga física de los operadores durante el entrenamiento."},"item_ticketgacha_standard_single":{"name":"Permiso de C.R. Básica","usage":"Un certificado interno de Endfield Industries. Usa esto para realizar 1 Caza de reclutas en [Caza de reclutas básica].","desc":"Endfield Industries tiene muchas conexiones y recursos en todo Talos-II. Cada vez que la División de RR. HH. de Endfield comienza la caza de reclutas en un sector particular de la industria, siempre habrá alguien que responda al llamado."},"ap_supply_lt_n":{"name":"Refuerzo de Cordura de emergencia","usage":"Usa esto para recuperar 40 de Cordura. Este objeto tiene fecha de caducidad.","desc":"Dosis moderada de jarabe de Cordura en un paquete para usar en caso de emergencia. Parece que el desarrollador consiguió una fórmula secreta en unos documentos extraños que multiplican la cantidad de azúcar en esta preparación específica."},"item_bp_double_reward":{"name":"Permiso de uso de Cordura","usage":"Usalo para consumir doble Cordura y obtener recompensas dobles a partir de modos de juego que consumen Cordura. Debe utilizarse 1 permiso por cada 10 de Cordura consumida.","desc":"Un permiso que consume de inmediato una enorme cantidad de Cordura. Un agotamiento excesivo de Cordura es extremadamente dañino para el cuerpo humano. Antes de continuar, deberás someterte a un examen médico completo de la División médica."},"item_char_break_stage_3_4":{"name":"Protoconjunto","usage":"Un material que permite ascender a los operadores a E3 o E4.","desc":"Un disco especial fabricado mediante el uso de tecno protocolo y avanzados procesos de grabado de datos. Se utiliza comúnmente con otros dispositivos para aliviar eficazmente la fatiga física de los operadores durante el entrenamiento."},"item_expcard_stage2_high":{"name":"Portador cognitivo avanzado","usage":"Un material que otorga mucha EXP para subir de nivel a operadores de Nvl. 61-90.","desc":"Unidad de almacenamiento desarrollada por Endfield Industries. Es compatible con diversos dispositivos de acceso a datos. Los nuevos operadores pueden utilizarlo para adquirir conocimientos de combate de manera efectiva. Gracias al apoyo brindado por la Cábala de la Tranquilidad, este transportador cuenta con tecnología de compresión de datos, lo que le permite almacenar aún más información."},"item_weapon_break_high":{"name":"Molde de fundición pesado","usage":"Un material que aumenta las armas.","desc":"Un molde de fundición pesado fabricado con materiales poco comunes. La activación Tecno protocolo permite que este molde mejore la fortaleza general de los materiales de las armas."},"item_char_skill_level_7_12":{"name":"Protoedro","usage":"Un material que mejora las habilidades de los operadores.","desc":"Un poliedro especial de cristal fabricado mediante Tecno protocolo y procesos avanzados de cristalización. A menudo se combina con otros dispositivos para mejorar la absorción fisiológica de los materiales de mejora."},"item_case_bp_selfselect_skillsp_1":{"name":"Caja de Selección de Progresión Avanzada Ⅰ","usage":"Al abrirla, te permite obtener el material de progresión avanzada de tu elección.","desc":"Una caja que contiene todo tipo de materiales de uso general de alta calidad. El rendimiento en combate de un operador no está limitado por su raza ni por su experiencia en batalla. A veces, solo necesitan un poco de inspiración."}},"errMsg":{"code_2000":"No se pudieron enviar las recompensas. Por favor espera e inténtalo de nuevo.","rewardClaimed":"Esta recompensa ya fue reclamada","code_1002":"El evento se está cargando, por favor espera un momento antes de volver a entrar en la pantalla del evento","code_1003":"El evento ha terminado","networkError":"Error del servicio"},"gamepad":{"hint":{"confirm":"Confirmar","close":"Off","closeCurrent":"Cerrar esta pantalla","exit":"Salir de la página"}}}'),i={lang:n.ELanguage["es-mx"],text:r,fonts:{}}}}]);
